/* ==== BEGIN verbatim: ngx_http_parse_complex_uri() ================= */
ngx_int_t
ngx_http_parse_complex_uri(ngx_http_request_t *r, ngx_uint_t merge_slashes)
{
    u_char  c, ch, decoded, *p, *u;
    enum {
        sw_usual = 0,
        sw_slash,
        sw_dot,
        sw_dot_dot,
        sw_quoted,
        sw_quoted_second
    } state, quoted_state;

#if (NGX_SUPPRESS_WARN)
    decoded = '\0';
    quoted_state = sw_usual;
#endif

    state = sw_usual;
    p = r->uri_start;
    u = r->uri.data;
    r->uri_ext = NULL;
    r->args_start = NULL;

    if (r->empty_path_in_uri) {
        *u++ = '/';
    }

    ch = *p++;

    while (p <= r->uri_end) {

        /*
         * we use "ch = *p++" inside the cycle, but this operation is safe,
         * because after the URI there is always at least one character:
         * the line feed
         */

        ngx_log_debug3(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
                       "s:%d in:'%Xd:%c'", state, ch, ch);

        switch (state) {

        case sw_usual:

            if (usual[ch >> 5] & (1U << (ch & 0x1f))) {
                *u++ = ch;
                ch = *p++;
                break;
            }

            switch (ch) {
#if (NGX_WIN32)
            case '\\':
                if (u - 2 >= r->uri.data
                    && *(u - 1) == '.' && *(u - 2) != '.')
                {
                    u--;
                }

                r->uri_ext = NULL;

                if (p == r->uri_start + r->uri.len) {

                    /*
                     * we omit the last "\" to cause redirect because
                     * the browsers do not treat "\" as "/" in relative URL path
                     */

                    break;
                }

                state = sw_slash;
                *u++ = '/';
                break;
#endif
            case '/':
#if (NGX_WIN32)
                if (u - 2 >= r->uri.data
                    && *(u - 1) == '.' && *(u - 2) != '.')
                {
                    u--;
                }
#endif
                r->uri_ext = NULL;
                state = sw_slash;
                *u++ = ch;
                break;
            case '%':
                quoted_state = state;
                state = sw_quoted;
                break;
            case '?':
                r->args_start = p;
                goto args;
            case '#':
                goto done;
            case '.':
                r->uri_ext = u + 1;
                *u++ = ch;
                break;
            case '+':
                r->plus_in_uri = 1;
                /* fall through */
            default:
                *u++ = ch;
                break;
            }

            ch = *p++;
            break;

        case sw_slash:

            if (usual[ch >> 5] & (1U << (ch & 0x1f))) {
                state = sw_usual;
                *u++ = ch;
                ch = *p++;
                break;
            }

            switch (ch) {
#if (NGX_WIN32)
            case '\\':
                break;
#endif
            case '/':
                if (!merge_slashes) {
                    *u++ = ch;
                }
                break;
            case '.':
                state = sw_dot;
                *u++ = ch;
                break;
            case '%':
                quoted_state = state;
                state = sw_quoted;
                break;
            case '?':
                r->args_start = p;
                goto args;
            case '#':
                goto done;
            case '+':
                r->plus_in_uri = 1;
                /* fall through */
            default:
                state = sw_usual;
                *u++ = ch;
                break;
            }

            ch = *p++;
            break;

        case sw_dot:

            if (usual[ch >> 5] & (1U << (ch & 0x1f))) {
                state = sw_usual;
                *u++ = ch;
                ch = *p++;
                break;
            }

            switch (ch) {
#if (NGX_WIN32)
            case '\\':
#endif
            case '/':
                state = sw_slash;
                u--;
                break;
            case '.':
                state = sw_dot_dot;
                *u++ = ch;
                break;
            case '%':
                quoted_state = state;
                state = sw_quoted;
                break;
            case '?':
                u--;
                r->args_start = p;
                goto args;
            case '#':
                u--;
                goto done;
            case '+':
                r->plus_in_uri = 1;
                /* fall through */
            default:
                state = sw_usual;
                *u++ = ch;
                break;
            }

            ch = *p++;
            break;

        case sw_dot_dot:

            if (usual[ch >> 5] & (1U << (ch & 0x1f))) {
                state = sw_usual;
                *u++ = ch;
                ch = *p++;
                break;
            }

            switch (ch) {
#if (NGX_WIN32)
            case '\\':
#endif
            case '/':
            case '?':
            case '#':
                u -= 4;
                for ( ;; ) {
                    if (u < r->uri.data) {
                        return NGX_HTTP_PARSE_INVALID_REQUEST;
                    }
                    if (*u == '/') {
                        u++;
                        break;
                    }
                    u--;
                }
                if (ch == '?') {
                    r->args_start = p;
                    goto args;
                }
                if (ch == '#') {
                    goto done;
                }
                state = sw_slash;
                break;
            case '%':
                quoted_state = state;
                state = sw_quoted;
                break;
            case '+':
                r->plus_in_uri = 1;
                /* fall through */
            default:
                state = sw_usual;
                *u++ = ch;
                break;
            }

            ch = *p++;
            break;

        case sw_quoted:
            r->quoted_uri = 1;

            if (ch >= '0' && ch <= '9') {
                decoded = (u_char) (ch - '0');
                state = sw_quoted_second;
                ch = *p++;
                break;
            }

            c = (u_char) (ch | 0x20);
            if (c >= 'a' && c <= 'f') {
                decoded = (u_char) (c - 'a' + 10);
                state = sw_quoted_second;
                ch = *p++;
                break;
            }

            return NGX_HTTP_PARSE_INVALID_REQUEST;

        case sw_quoted_second:
            if (ch >= '0' && ch <= '9') {
                ch = (u_char) ((decoded << 4) + (ch - '0'));

                if (ch == '%' || ch == '#') {
                    state = sw_usual;
                    *u++ = ch;
                    ch = *p++;
                    break;

                } else if (ch == '\0') {
                    return NGX_HTTP_PARSE_INVALID_REQUEST;
                }

                state = quoted_state;
                break;
            }

            c = (u_char) (ch | 0x20);
            if (c >= 'a' && c <= 'f') {
                ch = (u_char) ((decoded << 4) + (c - 'a') + 10);

                if (ch == '?') {
                    state = sw_usual;
                    *u++ = ch;
                    ch = *p++;
                    break;

                } else if (ch == '+') {
                    r->plus_in_uri = 1;
                }

                state = quoted_state;
                break;
            }

            return NGX_HTTP_PARSE_INVALID_REQUEST;
        }
    }

    if (state == sw_quoted || state == sw_quoted_second) {
        return NGX_HTTP_PARSE_INVALID_REQUEST;
    }

    if (state == sw_dot) {
        u--;

    } else if (state == sw_dot_dot) {
        u -= 4;

        for ( ;; ) {
            if (u < r->uri.data) {
                return NGX_HTTP_PARSE_INVALID_REQUEST;
            }

            if (*u == '/') {
                u++;
                break;
            }

            u--;
        }
    }

done:

    r->uri.len = u - r->uri.data;

    if (r->uri_ext) {
        r->exten.len = u - r->uri_ext;
        r->exten.data = r->uri_ext;
    }

    r->uri_ext = NULL;

    return NGX_OK;

args:

    while (p < r->uri_end) {
        if (*p++ != '#') {
            continue;
        }

        r->args.len = p - 1 - r->args_start;
        r->args.data = r->args_start;
        r->args_start = NULL;

        break;
    }

    r->uri.len = u - r->uri.data;

    if (r->uri_ext) {
        r->exten.len = u - r->uri_ext;
        r->exten.data = r->uri_ext;
    }

    r->uri_ext = NULL;

    return NGX_OK;
}
/* ==== END verbatim: ngx_http_parse_complex_uri() =================== */


/* ==== BEGIN authored wrapper ======================================= */
/*
 * nginx_normalize_path: normalize one origin-form path exactly as nginx does.
 *
 *   in, in_len     raw path bytes (need NOT be NUL-terminated; may be empty)
 *   merge_slashes  fuzzer input: 1 = collapse "//" (nginx default), 0 = keep
 *   out            caller buffer; must have capacity >= in_len + 1
 *   out_cap        capacity of out
 *   out_len        set to the normalized path length on success
 *
 * returns:
 *    0  success (out[0..*out_len) is the normalized path)
 *   -1  nginx rejected the path (parse error / invalid request)
 *   -2  out_cap too small (should never happen if out_cap >= in_len + 1)
 *
 * Faithfulness notes:
 *   - parse_complex_uri reads ONE byte at *uri_end (and discards it), matching
 *     nginx's "there is always a LF after the URI" invariant. We copy the
 *     input into a len+1 buffer with a trailing '\n' so that read is always
 *     valid regardless of what the caller's slice guarantees.
 *   - Normalization only shrinks or keeps length (%XX -> 1 byte, "."/".."/"//"
 *     removal), so out never needs more than in_len bytes; +1 covers the
 *     (origin-form-unreachable) empty_path leading-slash case for parity.
 *   - The "simple URI" branch returns the input path unchanged, exactly as
 *     ngx_http_process_request_uri() does when no flag is set.
 */
int
nginx_normalize_path(const unsigned char *in, size_t in_len,
                     int merge_slashes,
                     unsigned char *out, size_t out_cap, size_t *out_len)
{
    ngx_http_request_t  r;
    u_char             *inbuf, *nbuf;
    int                 rc = 0;

    memset(&r, 0, sizeof(r));

    inbuf = (u_char *) malloc(in_len + 1);
    nbuf  = (u_char *) malloc(in_len + 1);
    if (inbuf == NULL || nbuf == NULL) {
        free(inbuf);
        free(nbuf);
        return -1;
    }

    if (in_len) {
        memcpy(inbuf, in, in_len);
    }
    inbuf[in_len] = '\n';   /* nginx invariant: a LF follows the URI */

    r.uri_start = inbuf;
    r.uri_end   = inbuf + in_len;

    /* stage 1: origin-form parse (sets complex_uri/quoted_uri/args_start/...) */
    if (ngx_http_parse_uri(&r) != NGX_OK) {
        rc = -1;
        goto done;
    }

    /* reproduce the Linux path of ngx_http_process_request_uri() */
    if (r.args_start) {
        r.uri.len = (size_t) (r.args_start - 1 - r.uri_start);
    } else {
        r.uri.len = (size_t) (r.uri_end - r.uri_start);
    }

    if (r.complex_uri || r.quoted_uri || r.empty_path_in_uri) {
        if (r.empty_path_in_uri) {
            r.uri.len++;
        }
        r.uri.data = nbuf;

        if (ngx_http_parse_complex_uri(&r, merge_slashes ? 1 : 0) != NGX_OK) {
            rc = -1;
            goto done;
        }
    } else {
        r.uri.data = r.uri_start;   /* no normalization needed */
    }

    if (r.uri.len > out_cap) {
        rc = -2;
        goto done;
    }

    if (r.uri.len) {
        memcpy(out, r.uri.data, r.uri.len);
    }
    *out_len = r.uri.len;

done:
    free(inbuf);
    free(nbuf);
    return rc;
}
/* ==== END authored wrapper ========================================= */
